#include <iostream>\n#include <vector>\n\nclass Graph {\n public:\n  Graph() = default;\n  explicit Graph(int n, int m) : n_(n), m_(m) {\n    table_.resize(n_);\n    matches_.resize(m_, -1);\n  }\n\n  ~Graph() = default;\n\n  void AddVertex(int a, const std::vector<int>& vertexes) {\n    table_[a] = vertexes;\n  }\n\n  bool Dfs(int a) {\n    if (used_[a]) {\n      return false;\n    }\n    used_[a] = true;\n    for (int v : table_[a]) {\n      if (matches_[v] == -1 || Dfs(matches_[v])) {\n        matches_[v] = a;\n        return true;\n      }\n    }\n    return false;\n  }\n\n  std::vector<int> FindMatches() {\n    for (int i = 0; i < n_; i++) {\n      used_.assign(n_, false);\n      Dfs(i);\n    }\n    return matches_;\n  }\n\n private:\n  int n_;\n  int m_;\n  std::vector<int> matches_;\n  std::vector<bool> used_;\n  std::vector<std::vector<int>> table_;\n};\n\nint main() {\n  int n = 0;\n  int m = 0;\n  std::cin >> n >> m;\n  Graph g(n, m);\n\n  for (int i = 0; i < n; i++) {\n    std::vector<int> verts;\n    int v = 0;\n    std::cin >> v;\n    while (v != 0) {\n      verts.push_back(v - 1);\n      std::cin >> v;\n    }\n    g.AddVertex(i, verts);\n  }\n\n  std::vector<int> matches = g.FindMatches();\n\n  int counter = 0;\n  for (int i = 0; i < m; i++) {\n    if (matches[i] != -1) {\n      counter++;\n    }\n  }\n  std::cout << counter << '\\n';\n\n  for (int i = 0; i < m; i++) {\n    if (matches[i] != -1) {\n      std::cout << matches[i] + 1 << ' ' << i + 1 << '\\n';\n    }\n  }\n  return 0;\n}\n